import { Device, DeviceCapabilities, DeviceEvent } from './Device.js';
import type { PrecisionClock } from '@psyforge/timing';

export interface VideoDeviceInfo {
  deviceId: string;
  label: string;
  facingMode?: 'user' | 'environment';
  resolution?: {
    width: number;
    height: number;
  };
}

export interface VideoEventData {
  width?: number;
  height?: number;
  frameRate?: number;
  stream?: MediaStream;
}

export class VideoDevice extends Device {
  private mediaStream?: MediaStream;
  private videoElement?: HTMLVideoElement;
  private isRecording: boolean = false;

  constructor(clock: PrecisionClock) {
    const capabilities: DeviceCapabilities = {
      canDetectHotplug: true,
      supportsHighPrecisionTiming: true,
      supportedFormats: ['video/webm', 'video/mp4']
    };

    super('video-primary', 'video', capabilities, clock);
  }

  async initialize(): Promise<void> {
    if (this._isConnected) {
      return;
    }

    // Check if video is supported
    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
      throw new Error('Video capture not supported on this device');
    }

    this.setConnected(true);

    // Monitor device changes
    navigator.mediaDevices.addEventListener('devicechange', this.handleDeviceChange.bind(this));
  }

  async cleanup(): Promise<void> {
    await this.stopCapture();

    if (this.videoElement) {
      this.videoElement.pause();
      this.videoElement.srcObject = null;
      this.videoElement = undefined;
    }

    navigator.mediaDevices?.removeEventListener('devicechange', this.handleDeviceChange.bind(this));

    this.setConnected(false);
  }

  async detectCapabilities(): Promise<DeviceCapabilities> {
    if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
      return {
        canDetectHotplug: false,
        supportsHighPrecisionTiming: false,
        supportedFormats: []
      };
    }

    const devices = await this.getVideoDevices();
    const hasCamera = devices.length > 0;

    return {
      canDetectHotplug: true,
      supportsHighPrecisionTiming: true,
      supportedFormats: hasCamera ? ['video/webm', 'video/mp4'] : []
    };
  }

  async getVideoDevices(): Promise<VideoDeviceInfo[]> {
    if (!navigator.mediaDevices || !navigator.mediaDevices.enumerateDevices) {
      return [];
    }

    try {
      const devices = await navigator.mediaDevices.enumerateDevices();
      return devices
        .filter(device => device.kind === 'videoinput')
        .map(device => {
          const info: VideoDeviceInfo = {
            deviceId: device.deviceId,
            label: device.label
          };
          const facingMode = this.inferFacingMode(device.label);
          if (facingMode) {
            info.facingMode = facingMode;
          }
          return info;
        });
    } catch (error) {
      console.error('Error enumerating video devices:', error);
      return [];
    }
  }

  async startCapture(
    deviceId?: string,
    constraints?: {
      width?: number;
      height?: number;
      frameRate?: number;
      facingMode?: 'user' | 'environment';
    }
  ): Promise<MediaStream> {
    if (this.isRecording) {
      throw new Error('Video capture already active');
    }

    try {
      const videoConstraints: MediaTrackConstraints = {
        ...constraints
      };

      if (deviceId) {
        videoConstraints.deviceId = { exact: deviceId };
      }

      const mediaConstraints: MediaStreamConstraints = {
        video: videoConstraints,
        audio: false
      };

      this.mediaStream = await navigator.mediaDevices.getUserMedia(mediaConstraints);
      this.isRecording = true;

      // Get actual video settings
      const videoTrack = this.mediaStream.getVideoTracks()[0];
      const settings = videoTrack?.getSettings() || {};

      this.emitEvent('capturestarted', {
        width: settings.width,
        height: settings.height,
        frameRate: settings.frameRate,
        stream: this.mediaStream
      });

      return this.mediaStream;

    } catch (error) {
      throw new Error(`Failed to start video capture: ${error}`);
    }
  }

  async stopCapture(): Promise<void> {
    if (!this.isRecording) {
      return;
    }

    if (this.mediaStream) {
      this.mediaStream.getTracks().forEach(track => track.stop());
      this.mediaStream = undefined;
    }

    this.isRecording = false;
    this.emitEvent('capturestopped', { stopped: true });
  }

  async createVideoElement(): Promise<HTMLVideoElement> {
    if (!this.mediaStream) {
      throw new Error('No active video stream. Call startCapture() first.');
    }

    this.videoElement = document.createElement('video');
    this.videoElement.autoplay = true;
    this.videoElement.playsInline = true;
    this.videoElement.muted = true;
    this.videoElement.srcObject = this.mediaStream;

    return new Promise((resolve, reject) => {
      if (!this.videoElement) {
        reject(new Error('Failed to create video element'));
        return;
      }

      this.videoElement.onloadedmetadata = () => {
        if (this.videoElement) {
          this.emitEvent('videoelement', {
            width: this.videoElement.videoWidth,
            height: this.videoElement.videoHeight
          });
          resolve(this.videoElement);
        }
      };

      this.videoElement.onerror = () => {
        reject(new Error('Failed to load video stream'));
      };
    });
  }

  async captureFrame(): Promise<ImageData | null> {
    if (!this.videoElement || !this.isRecording) {
      return null;
    }

    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');

    if (!ctx) {
      throw new Error('Failed to get canvas context');
    }

    canvas.width = this.videoElement.videoWidth;
    canvas.height = this.videoElement.videoHeight;

    ctx.drawImage(this.videoElement, 0, 0);

    return ctx.getImageData(0, 0, canvas.width, canvas.height);
  }

  async takePhoto(): Promise<Blob> {
    if (!this.videoElement || !this.isRecording) {
      throw new Error('No active video stream');
    }

    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');

    if (!ctx) {
      throw new Error('Failed to get canvas context');
    }

    canvas.width = this.videoElement.videoWidth;
    canvas.height = this.videoElement.videoHeight;

    ctx.drawImage(this.videoElement, 0, 0);

    return new Promise((resolve, reject) => {
      canvas.toBlob((blob) => {
        if (blob) {
          this.emitEvent('phototaken', {
            width: canvas.width,
            height: canvas.height
          });
          resolve(blob);
        } else {
          reject(new Error('Failed to create photo blob'));
        }
      }, 'image/jpeg', 0.8);
    });
  }

  private inferFacingMode(label: string): 'user' | 'environment' | undefined {
    const lowerLabel = label.toLowerCase();
    if (lowerLabel.includes('front') || lowerLabel.includes('user')) {
      return 'user';
    }
    if (lowerLabel.includes('back') || lowerLabel.includes('rear') || lowerLabel.includes('environment')) {
      return 'environment';
    }
    return undefined;
  }

  private handleDeviceChange(): void {
    this.emitEvent('devicechange', { changed: true });
  }

  get stream(): MediaStream | undefined {
    return this.mediaStream;
  }

  get video(): HTMLVideoElement | undefined {
    return this.videoElement;
  }
}

