import { PrecisionClock } from '@psyforge/timing';
import { Task, TaskState } from './Task.js';
import { TaskPriority, TaskPriorityUtils } from './TaskPriority.js';
import { Timeline } from './Timeline.js';

/**
 * Scheduled task entry with timing information
 */
interface ScheduledTask {
  task: Task;
  scheduledTime: number;
  frameNumber: number;
  timeline?: Timeline;
}

/**
 * Scheduler performance metrics
 */
export interface SchedulerMetrics {
  /** Number of tasks executed */
  tasksExecuted: number;
  /** Number of tasks that executed late */
  lateExecutions: number;
  /** Average timing error in milliseconds */
  averageTimingError: number;
  /** Maximum timing error observed */
  maxTimingError: number;
  /** Current queue length */
  queueLength: number;
  /** Frame rate (tasks per second) */
  frameRate: number;
  /** CPU usage estimate (0-1) */
  cpuUsage: number;
}

/**
 * Scheduler configuration options
 */
export interface SchedulerOptions {
  /** Maximum tasks to execute per frame */
  maxTasksPerFrame?: number;
  /** Maximum frame time budget in milliseconds */
  frameTimeBudget?: number;
  /** Whether to use high-precision timing */
  useHighPrecisionTiming?: boolean;
  /** Timing error tolerance in milliseconds */
  timingTolerance?: number;
  /** Whether to preempt lower priority tasks */
  allowPreemption?: boolean;
}

/**
 * Hierarchical task scheduler with precise timing control
 * Manages experiment execution with sub-millisecond timing accuracy
 */
export class Scheduler {
  private readonly _clock: PrecisionClock;
  private readonly _options: Required<SchedulerOptions>;

  private _taskQueue: ScheduledTask[] = [];
  private _runningTasks: Set<Task> = new Set();
  private _timelines: Set<Timeline> = new Set();
  private _isRunning: boolean = false;
  private _frameHandle: number | null = null;
  private _frameNumber: number = 0;

  // Performance tracking
  private _metrics: SchedulerMetrics = {
    tasksExecuted: 0,
    lateExecutions: 0,
    averageTimingError: 0,
    maxTimingError: 0,
    queueLength: 0,
    frameRate: 0,
    cpuUsage: 0
  };
  private _timingErrors: number[] = [];
  private _frameStartTime: number = 0;

  constructor(options: SchedulerOptions = {}) {
    this._options = {
      maxTasksPerFrame: options.maxTasksPerFrame ?? 10,
      frameTimeBudget: options.frameTimeBudget ?? 8, // 8ms for 120fps headroom
      useHighPrecisionTiming: options.useHighPrecisionTiming ?? true,
      timingTolerance: options.timingTolerance ?? 2, // 2ms tolerance
      allowPreemption: options.allowPreemption ?? true
    };

    this._clock = new PrecisionClock();
  }

  /**
   * Current scheduler metrics
   */
  get metrics(): Readonly<SchedulerMetrics> {
    return { ...this._metrics };
  }

  /**
   * Whether scheduler is running
   */
  get isRunning(): boolean {
    return this._isRunning;
  }

  /**
   * Number of tasks in queue
   */
  get queueLength(): number {
    return this._taskQueue.length;
  }

  /**
   * Number of currently running tasks
   */
  get runningTaskCount(): number {
    return this._runningTasks.size;
  }

  /**
   * Start the scheduler
   */
  start(): void {
    if (this._isRunning) return;

    this._isRunning = true;
    this._frameNumber = 0;
    this._scheduleNextFrame();
  }

  /**
   * Stop the scheduler
   */
  stop(): void {
    if (!this._isRunning) return;

    this._isRunning = false;

    if (this._frameHandle !== null) {
      cancelAnimationFrame(this._frameHandle);
      this._frameHandle = null;
    }

    // Cancel all running tasks
    for (const task of this._runningTasks) {
      task.cancel(new Error('Scheduler stopped'));
    }
    this._runningTasks.clear();

    // Stop all timelines
    for (const timeline of this._timelines) {
      if (timeline.isRunning) {
        timeline.stop();
      }
    }
  }

  /**
   * Schedule a task to execute at a specific time
   */
  scheduleTask(task: Task, executeAt: number): void {
    if (!this._isRunning) {
      throw new Error('Scheduler is not running');
    }

    const scheduledTask: ScheduledTask = {
      task,
      scheduledTime: executeAt,
      frameNumber: this._frameNumber
    };

    this._insertTaskByPriority(scheduledTask);
    this._metrics.queueLength = this._taskQueue.length;
  }

  /**
   * Schedule a task to execute after a delay
   */
  scheduleDelayed(task: Task, delayMs: number): void {
    const executeAt = this._clock.now() + delayMs;
    this.scheduleTask(task, executeAt);
  }

  /**
   * Schedule a task to execute on the next frame
   */
  scheduleNextFrame(task: Task): void {
    const nextFrameTime = this._clock.now() + 16.67; // ~60fps
    this.scheduleTask(task, nextFrameTime);
  }

  /**
   * Add a timeline to be managed by the scheduler
   */
  addTimeline(timeline: Timeline): void {
    this._timelines.add(timeline);

    // Schedule timeline start
    const startTask = new Task(`Start ${timeline.name}`, async () => {
      await timeline.start();
    }, { priority: TaskPriority.HIGH });

    this.scheduleNextFrame(startTask);
  }

  /**
   * Remove a timeline from scheduler management
   */
  removeTimeline(timeline: Timeline): void {
    this._timelines.delete(timeline);

    if (timeline.isRunning) {
      timeline.stop();
    }
  }

  /**
   * Cancel a specific task
   */
  cancelTask(task: Task): boolean {
    // Remove from queue
    const queueIndex = this._taskQueue.findIndex(st => st.task === task);
    if (queueIndex !== -1) {
      this._taskQueue.splice(queueIndex, 1);
      task.cancel(new Error('Task cancelled by scheduler'));
      this._metrics.queueLength = this._taskQueue.length;
      return true;
    }

    // Cancel if running
    if (this._runningTasks.has(task)) {
      task.cancel(new Error('Task cancelled by scheduler'));
      this._runningTasks.delete(task);
      return true;
    }

    return false;
  }

  /**
   * Clear all pending tasks
   */
  clearQueue(): void {
    for (const scheduledTask of this._taskQueue) {
      scheduledTask.task.cancel(new Error('Queue cleared'));
    }
    this._taskQueue = [];
    this._metrics.queueLength = 0;
  }

  /**
   * Get tasks scheduled for a specific time range
   */
  getScheduledTasks(startTime: number, endTime: number): ScheduledTask[] {
    return this._taskQueue.filter(st => 
      st.scheduledTime >= startTime && st.scheduledTime <= endTime
    );
  }

  /**
   * Reset scheduler metrics
   */
  resetMetrics(): void {
    this._metrics = {
      tasksExecuted: 0,
      lateExecutions: 0,
      averageTimingError: 0,
      maxTimingError: 0,
      queueLength: this._taskQueue.length,
      frameRate: 0,
      cpuUsage: 0
    };
    this._timingErrors = [];
  }

  /**
   * Schedule next frame execution
   * @private
   */
  private _scheduleNextFrame(): void {
    if (!this._isRunning) return;

    this._frameHandle = requestAnimationFrame(() => {
      this._executeFrame();
      this._scheduleNextFrame();
    });
  }

  /**
   * Execute tasks for current frame
   * @private
   */
  private async _executeFrame(): Promise<void> {
    this._frameStartTime = this._clock.now();
    this._frameNumber++;

    const currentTime = this._frameStartTime;
    let executedCount = 0;
    let frameTimeUsed = 0;

    // Get tasks ready for execution
    const readyTasks = this._getReadyTasks(currentTime);

    for (const scheduledTask of readyTasks) {
      if (!this._isRunning) break;

      // Check frame budget
      if (executedCount >= this._options.maxTasksPerFrame) break;
      if (frameTimeUsed >= this._options.frameTimeBudget) break;

      // Check if task was cancelled
      if (scheduledTask.task.state !== TaskState.PENDING) continue;

      try {
        const taskStartTime = this._clock.now();

        this._runningTasks.add(scheduledTask.task);

        await scheduledTask.task.execute(
          scheduledTask.scheduledTime,
          taskStartTime,
          this._frameNumber
        );

        this._runningTasks.delete(scheduledTask.task);

        const taskEndTime = this._clock.now();
        const executionTime = taskEndTime - taskStartTime;
        const timingError = taskStartTime - scheduledTask.scheduledTime;

        // Update metrics
        this._updateMetrics(timingError, executionTime);

        executedCount++;
        frameTimeUsed = taskEndTime - this._frameStartTime;

      } catch (error) {
        this._runningTasks.delete(scheduledTask.task);
        console.error(`Task execution failed:`, error);
      }

      // Remove executed task from queue
      const index = this._taskQueue.indexOf(scheduledTask);
      if (index !== -1) {
        this._taskQueue.splice(index, 1);
      }
    }

    // Update frame rate and CPU usage
    const frameTime = this._clock.now() - this._frameStartTime;
    this._metrics.frameRate = executedCount > 0 ? 1000 / frameTime : 0;
    this._metrics.cpuUsage = Math.min(frameTime / this._options.frameTimeBudget, 1);
    this._metrics.queueLength = this._taskQueue.length;
  }

  /**
   * Get tasks ready for execution based on current time
   * @private
   */
  private _getReadyTasks(currentTime: number): ScheduledTask[] {
    const tolerance = this._options.timingTolerance;

    return this._taskQueue
      .filter(st => st.scheduledTime <= currentTime + tolerance)
      .sort((a, b) => {
        // First sort by priority (higher priority first)
        const priorityDiff = TaskPriorityUtils.compare(a.task.priority, b.task.priority);
        if (priorityDiff !== 0) return priorityDiff;

        // Then by scheduled time (earlier first)
        return a.scheduledTime - b.scheduledTime;
      });
  }

  /**
   * Insert task into queue maintaining priority order
   * @private
   */
  private _insertTaskByPriority(scheduledTask: ScheduledTask): void {
    const insertIndex = this._taskQueue.findIndex(st => 
      TaskPriorityUtils.compare(scheduledTask.task.priority, st.task.priority) < 0 ||
      (scheduledTask.task.priority === st.task.priority && 
       scheduledTask.scheduledTime < st.scheduledTime)
    );

    if (insertIndex === -1) {
      this._taskQueue.push(scheduledTask);
    } else {
      this._taskQueue.splice(insertIndex, 0, scheduledTask);
    }
  }

  /**
   * Update performance metrics
   * @private
   */
  private _updateMetrics(timingError: number, _executionTime: number): void {
    this._metrics.tasksExecuted++;

    const absTimingError = Math.abs(timingError);
    if (absTimingError > this._options.timingTolerance) {
      this._metrics.lateExecutions++;
    }

    this._timingErrors.push(absTimingError);
    this._metrics.maxTimingError = Math.max(this._metrics.maxTimingError, absTimingError);

    // Calculate rolling average timing error (last 100 tasks)
    if (this._timingErrors.length > 100) {
      this._timingErrors.shift();
    }
    this._metrics.averageTimingError = 
      this._timingErrors.reduce((sum, err) => sum + err, 0) / this._timingErrors.length;
  }

  /**
   * String representation for debugging
   */
  toString(): string {
    return `Scheduler(running: ${this._isRunning}, queue: ${this._taskQueue.length}, running: ${this._runningTasks.size})`;
  }
}

